+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})[ \	]+(.+?)\\s*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const eol = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const {start, end, headings} = this.findTocAndHeadings(lines, options);
+
+    if (start === -1) {
+      return text;
+    }
+
+    const toc = this.buildToc(headings, options);
+    const suffix = lines.slice(end === -1 ? start + 1 : end + 1);
+    while (suffix[0] === '') {
+      suffix.shift();
+    }
+
+    const replacement = [
+      lines[start],
+      '',
+      ...(options.title === '' ? [] : [options.title, '']),
+      ...toc,
+      '',
+      end === -1 ? '<!-- /toc -->' : lines[end],
+      '',
+    ];
+
+    if (suffix.length === 0) {
+      replacement.push('');
+    }
+
+    return [...lines.slice(0, start), ...replacement, ...suffix].join(eol);
+  }
+
+  private findTocAndHeadings(lines: string[], options: AutoTocOptions): {start: number, end: number, headings: Heading[]} {
+    let start = -1;
+    let end = -1;
+    let inYaml = lines[0]?.trim() === '---';
+    let inCodeFence: string = null;
+    let inMath = false;
+    const allHeadings: (Heading & {line: number})[] = [];
+
+    for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+      const line = lines[lineIndex];
+      if (inYaml) {
+        if (lineIndex > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) {
+          inYaml = false;
+        }
+        continue;
+      }
+
+      const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (fence) {
+        if (inCodeFence === null) {
+          inCodeFence = fence[1][0];
+        } else if (inCodeFence === fence[1][0]) {
+          inCodeFence = null;
+        }
+        continue;
+      }
+      if (inCodeFence !== null) {
+        continue;
+      }
+
+      if (/^\\s*\\$\\$/.test(line)) {
+        const closingOnSameLine = /^\\s*\\$\\$.*\\$\\$\\s*$/.test(line.slice(line.indexOf('$$') + 2));
+        if (!closingOnSameLine) {
+          inMath = !inMath;
+        }
+        continue;
+      }
+      if (inMath) {
+        continue;
+      }
+
+      if (start === -1 && startMarker.test(line)) {
+        start = lineIndex;
+        continue;
+      }
+      if (start !== -1 && end === -1 && endMarker.test(line)) {
+        end = lineIndex;
+        continue;
+      }
+
+      const match = line.match(atxHeading);
+      if (match) {
+        allHeadings.push({level: match[1].length, text: this.removeClosingHeadingHashes(match[2]), line: lineIndex});
+      }
+    }
+
+    return {
+      start,
+      end,
+      headings: allHeadings.filter((heading) =>
+        heading.level >= options.minLevel &&
+        heading.level <= options.maxLevel &&
+        !(end !== -1 && heading.line > start && heading.line < end) &&
+        !this.isExcluded(heading.text, options.excludeHeadings),
+      ),
+    };
+  }
+
+  private buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+    const anchors = new Map<string, number>();
+    return headings.map((heading, index) => {
+      const explicitId = options.useExplicitIds ? this.getExplicitId(heading.text) : null;
+      const displayText = this.removeExplicitId(heading.text);
+      const baseAnchor = explicitId ?? this.slugify(displayText);
+      const priorCount = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, priorCount + 1);
+      const anchor = priorCount === 0 ? baseAnchor : `${baseAnchor}-${priorCount}`;
+      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number'
+        ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`
+        : options.bulletMarker;
+      const label = options.stripFormattingInToc ? this.stripFormatting(displayText) : displayText;
+      return `${indentation}${marker} [${label}](#${anchor})`;
+    });
+  }
+
+  private isExcluded(heading: string, excluded: string[]): boolean {
+    const plainHeading = this.stripFormatting(this.removeExplicitId(heading));
+    return excluded.some((pattern) => {
+      const regexMatch = pattern.match(/^\\/(.*)\\/$/);
+      if (regexMatch) {
+        try {
+          return new RegExp(regexMatch[1], 'i').test(plainHeading);
+        } catch (_) {
+          return pattern.localeCompare(plainHeading, undefined, {sensitivity: 'accent'}) === 0;
+        }
+      }
+      return pattern.localeCompare(plainHeading, undefined, {sensitivity: 'accent'}) === 0;
+    });
+  }
+
+  private getExplicitId(heading: string): string | null {
+    return heading.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1] ?? null;
+  }
+
+  private removeExplicitId(heading: string): string {
+    return heading.replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '');
+  }
+
+  private slugify(heading: string): string {
+    return this.stripFormatting(heading)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+  }
+
+  private stripFormatting(text: string): string {
+    return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/!?\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display: string) => display ?? target)
+      .replace(/!?\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1')
+      .replace(/<[^>]*>/g, '')
+      .replace(/(?:\\*\\*|__|\\*|_|~~|`)/g, '');
+  }
+
+  private removeClosingHeadingHashes(heading: string): string {
+    return heading.replace(/[ \	]+#+\\s*$/, '');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Bullet list'}, {value: 'number', description: 'Numbered list'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Always use 1'}, {value: 'increment', description: 'Increment'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
