  private buildToc(headings: Heading[], options: AutoTocOptions): string[] {
    const anchors = new Map<string, number>();
    return headings.map((heading, index) => {
      const explicitId = options.useExplicitIds ? this.getExplicitId(heading.text) : null;
      const displayText = this.removeExplicitId(heading.text);
      const baseAnchor = explicitId ?? this.slugify(displayText);
      const priorCount = anchors.get(baseAnchor) ?? 0;
      anchors.set(baseAnchor, priorCount + 1);
      const anchor = priorCount === 0 ? baseAnchor : `${baseAnchor}-${priorCount}`;
      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
      const marker = options.listStyle === 'number' ?
        `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` :
        options.bulletMarker;
      const label = options.stripFormattingInToc ? this.stripFormatting(displayText) : displayText;
      return `${indentation}${marker} [${label}](#${anchor})`;
    });
